INSERT INTO public.milestones (milestone_id, age, area_id, area_name, skill_id, skill_name, description, question, science_fact, locale, media_jpg_content_type, media_jpg_file_name, media_mp4_content_type, media_mp4_file_name, source_data) VALUES
(38, 0, 1, 'Physical', 6, 'Sensory Development', 'Gets startled by loud sounds.', 'When your baby hears a loud sound, do they react suddenly (move)?', 'Loud or unfamiliar noises can surprise many of us, but more so infants, as their neurological development is still immature. As their brains develop, babies grow accustomed to normal, every day sounds and variances in volume.', 'en', NULL, NULL, 'video/mp4', '038_MilDes.mp4', 'Kinedu Research Team'),
(138, 0, 1, 'Physical', 6, 'Sensory Development', 'Responds positively to touch.', 'Does your baby calm down or seem to enjoy it when you hold or touch them?', 'Even after birth, senses like hearing and vision are limited as they continue to develop during the first few months. Touch becomes their default sense to explore their environment and connect with caregivers in the beginning.', 'en', NULL, NULL, 'video/mp4', '138_MilDes.mp4', 'Kinedu Research Team'),
(144, 0, 1, 'Physical', 6, 'Sensory Development', 'Intentionally turns their head towards one side upon touch.', 'When you gently touch your baby''s cheek or side, do they intentionally turn their head in that direction?', 'Your baby demonstrates intentional head movement by turning their head towards one side when touched. This action reflects their growing awareness and ability to respond to stimuli in their environment.', 'en', NULL, NULL, 'video/mp4', '144_MilDes.mp4', 'Kinedu Research Team'),
(21, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Stays curled up with arms and knees close to their body.', 'Does your baby usually stay curled up with arms and knees close to their body when lying down?', 'Babies take time to stretch out and relax their muscles after being in the womb for so long. They slowly develop strength to flex and extend their arms and legs. Babies enjoy a smooth transition to their new environment, so help recreate the safety they felt in the womb by swaddling.', 'en', 'image/jpeg', '021_MilDes.jpg', NULL, NULL, 'Kinedu Research Team'),
(131, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Grabs your finger or an object placed in their hand.', 'When you place your finger or a small object in your baby''s hand, do they grasp it?', 'Babies are born with several automatic reflexes, and grasping is one of them. This very strong reflex is triggered when anything presses on their palm, and it prepares them for voluntary grasping later on.', 'en', 'image/jpeg', '131_MilDes.jpg', NULL, NULL, 'Kinedu Research Team'),
(136, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Lies on their back with legs open in a butterfly position.', 'When lying on their back, does your baby keep their legs open in a butterfly position?', 'It takes several months for infant joints to stretch out. Babies instinctively place their legs in this type of position to prevent hip dysplasia or dislocation. It''s important to make sure any type of baby carrier or support being used is ergonomic and their hips and legs are loose when swaddled to prevent injury.', 'en', 'image/jpeg', '136_MilDes.jpg', NULL, NULL, 'Kinedu Research Team'),
(150, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Shows the Moro Reflex by raising their arms and stretching their back and neck when startled.', 'When startled, does your baby raise their arms and stretch their back and neck?', 'The Moro reflex is present from birth and disappears between 2 to 6 months of age. It''s an infant''s innate response to being startled, and is meant to protect them from harm. Unfortunately, it can also startle and wake them. Swaddling helps them feel more contained and less likely to be awaken by the reflex.', 'en', NULL, NULL, 'video/mp4', '150_MilDes.mp4', 'American Academy of Pediatrics'),
(193, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Demonstrates the Babinski Reflex by spreading their toes when the sole of their foot is touched.', 'When you gently stroke the sole of your baby''s foot, do they spread their toes?', 'The Babinsky reflex shows a healthy nervous system. It activates a muscle that produces toe-flexing, and is a normal response up until 2 years of age. After 2, this reflex could indicate a nervous system disorder.', 'en', NULL, NULL, 'video/mp4', '193_MilDes.mp4', 'American Academy of Pediatrics'),
(201, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Holds and clenches their fists tightly.', 'Does your baby often hold and clench their fists tightly?', 'Newborns hands stay clenched because of an innate grasping reflex. It''s the same position in the womb. Their fists should begin to loosen around 8 weeks after birth.', 'en', 'image/jpeg', '201_MilDes.jpg', NULL, NULL, 'Kinedu Research Team'),
(236, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Displays the Sucking Reflex by sucking when something touches the roof of their mouth.', 'When something touches the roof of your baby''s mouth, do they start sucking?', 'The sucking reflex has an evolutionary purpose because it allows babies to get milk. At 3 to 4 months, it''s no longer a reflex and is now a voluntary movement.', 'en', 'image/jpeg', '236_mildes.jpg', NULL, NULL, 'American Academy of Pediatrics'),
(285, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Smiles instinctively; this usually happens randomly, especially while sleeping.', 'Does your baby sometimes smile randomly, especially while sleeping?', 'The smile reflex is key to an infant''s survival instinct: it ensures their care by making them appear endearing to others. Smiling happens during sleep because the body goes through physiological changes that activate this reflex.', 'en', 'image/jpeg', '285_MilDes.jpg', NULL, NULL, 'Kinedu Research Team'),
(289, 0, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'Shows the Rooting Reflex by opening their mouth and turning toward your hand when you stroke their cheek.', 'When you stroke your baby''s cheek, do they open their mouth and turn toward your hand?', 'The rooting reflex is triggered by stroking the cheek, and it is meant to help babies find food. After 6 months, the reflex disappears.', 'en', NULL, NULL, 'video/mp4', '289_MilDes.mp4', 'American Academy of Pediatrics'),
(122, 1, 4, 'Social-emotional', 2, 'Secure Attachment', 'Becomes calm when hearing voices they know.', 'Does your baby become calmer when they hear voices they know?', 'Newborns recognize voices and other familiar sounds from the womb. Hearing these familiar sounds provides safety and an innate understanding their needs will be met.', 'en', NULL, NULL, 'video/mp4', '122_mildes.mp4', 'American Association for the Advancement of Science'),
(129, 1, 4, 'Social-emotional', 2, 'Secure Attachment', 'Responds positively to loving gestures.', 'Does your baby respond positively to loving gestures, like gentle cuddling or kisses?', 'To develop strong neural connections, babies need caregivers that are sensitive and responsive. These needs are met through serve and return interactions, such as eye contact, hugs, or words. When babies babble, gesture, or cry they need a response to develop social and communication skills.', 'en', 'image/jpeg', '129_mildes.jpg', NULL, NULL, 'Center on the Developing Child at Harvard University'),
(247, 1, 3, 'Lingustic', 3, 'Babbling', 'Makes guttural sounds, like ''ga'' or ''gu''.', 'Have you heard your baby make cooing or guttural sounds, like "ga" or "gu"?', 'Newborns communicate through crying and grunting because their vocal cords haven''t developed the ability to vibrate smoothly yet. So, even if they wanted to produce sounds that weren''t guttural, they physically aren''t able to yet!', 'en', 'image/jpeg', '247_mildes.jpg', NULL, NULL, 'Kinedu Research Team'),
(145, 1, 1, 'Physical', 6, 'Sensory Development', 'Looks in the direction of a noise.', 'Does your baby look in the direction of a noise?', 'Now, babies locate sound origins that come from horizontal locations, but can find it more difficult detecting sounds from a vertical location. The brain can detect these differences based on the time it takes for the sound to get to one ear compared to the other.', 'en', NULL, NULL, 'video/mp4', '145_MilDes.mp4', 'Center for Disease Control and Prevention'),
(303, 1, 1, 'Physical', 6, 'Sensory Development', 'Looks at the person speaking to them.', 'Does your baby look at the person speaking to them?', 'Babies are programmed to pay more attention to the human voice, especially the high-pitched tones of their native language. Even in a noisy room, babies have a preference for their caregiver''s voice and will pay attention to it.', 'en', NULL, NULL, 'video/mp4', '303_MilDes.mp4', 'Kinedu Research Team'),
(41, 1, 2, 'Cognitive', 7, 'Object Exploration', 'Brings their hands to their mouth.', 'Does your baby bring their hands to their mouth?', 'Since touch is the most developed sense in newborns, their hands and mouth are the most sensitive parts of their body. Exploring them allows them to get to know their own body.', 'en', 'image/jpeg', '041_MilDes.jpg', NULL, NULL, 'Center for Disease Control and Prevention'),
(86, 1, 1, 'Physical', 8, 'Coordination', 'When lying on their back, they lift and kick their legs.', 'When lying on their back, does your baby lift and kick their legs?', 'Scientists have garnered enough evidence to conclude that this movement has a positive impact on the development of motor skills.', 'en', NULL, NULL, 'video/mp4', '86_mildes.mp4', 'Kinedu Research Team'),
(146, 1, 1, 'Physical', 8, 'Coordination', 'Opens and closes their hands when you touch their palm.', 'Does your baby open and close their hands when you touch their palm?', 'As babies get used to being out of the womb they will start to stretch their hands a little more, but the grasping reflex is still very present and strong, so even if they unclench their fists a bit more now, they will close them tightly if you touch their palm.', 'en', NULL, NULL, 'video/mp4', '146_mildes.mp4', 'Kinedu Research Team'),
(75, 1, 1, 'Physical', 12, 'Head Control', 'When lying on their tummy, they lift their head for a short time.', 'When lying on their tummy, does your baby lift their head for a short time?', 'Starting tummy time from birth means working towards the development of stronger neck muscles. Strong neck muscles allow them to hold up their head and begin to see their environment. This takes lots of practice and repetition. Some babies don''t enjoy it, but there are lots of alternative positions that can help strengthen the neck this way.', 'en', NULL, NULL, 'video/mp4', '075_MilDes.mp4', 'Center for Disease Control and Prevention'),
(216, 1, 1, 'Physical', 12, 'Head Control', 'When lying on their back, they turn their head to the left and right.', 'When lying on their back, does your baby turn their head to the left and right?', 'This is a micro milestone that babies achieve en route to being able to roll to a face down position. It also visibly shows the neck muscles are becoming stronger.', 'en', NULL, NULL, 'video/mp4', '216_MilDes.mp4', 'Kinedu Research Team'),
(43, 1, 1, 'Physical', 19, 'Newborn Reflexes and Posture', 'When you press or hold their feet against a firm surface, they stretch their legs.', 'When you press or hold your baby''s feet against a firm surface, do they stretch their legs?', 'The part of the spinal chord needed for walking is fully developed by Week 12 in pregnancy. After birth, infants don''t have the strength to walk yet but they instintively stretch their legs this way (preparing for what''s to come!)', 'en', 'image/jpeg', '43_mildes.jpg', NULL, NULL, 'Kinedu Research Team'),
(240, 1, 4, 'Social-emotional', 22, 'Foundations of Social Development', 'Stares at people''s faces.', 'Does your baby stare at people''s faces?', 'An infant''s brain is wired to stare at faces, or anything that resembles a human face. This is an evolutionary trait meant to help babies bond with their caregivers.', 'en', 'image/jpeg', '240_mildes.jpg', NULL, NULL, 'Center for Disease Control and Prevention');
